    #[test]
    fn test_wire_roundtrip() {
        let receipt = MeshReceipt {
            rcf_identity: [0x11; 32],
            t_k_q1616: 42000,
            entity_id: 7,
            k_index: 999,
            parent_hash: [0x22; 16],
            disc_flag: DISC_NORMAL,
            receipt_hash: [0x33; 32],
            sigma_enc: 12345,
            sluice_state: 0x01,
            gap_t_k_numer: 0,
            gap_t_k_denom: 1,
            t_k_numer: 3,
            t_k_denom: 7,
            timestamp_ns: 1234567890,
            telemetry: crate::ledger::ChronoTelemetry::unattached(),
            thought: crate::ledger::ThoughtTelemetry::unattached(),
            dimensional: crate::ledger::DimensionalTelemetry::unattached(),
        };

        let wire = receipt_to_wire(&receipt);
        assert_eq!(wire.len(), WIRE_SIZE);

        let decoded = receipt_from_wire(&wire).expect("decode must succeed");
        assert_eq!(decoded.rcf_identity, receipt.rcf_identity);
        assert_eq!(decoded.t_k_q1616, receipt.t_k_q1616);
        assert_eq!(decoded.entity_id, receipt.entity_id);
        assert_eq!(decoded.k_index, receipt.k_index);
        assert_eq!(decoded.parent_hash, receipt.parent_hash);
        assert_eq!(decoded.disc_flag, receipt.disc_flag);
        assert_eq!(decoded.receipt_hash, receipt.receipt_hash);
        assert_eq!(decoded.sigma_enc, receipt.sigma_enc);
        assert_eq!(decoded.sluice_state, receipt.sluice_state);
        assert_eq!(decoded.gap_t_k_numer, receipt.gap_t_k_numer);
        assert_eq!(decoded.gap_t_k_denom, receipt.gap_t_k_denom);
        assert_eq!(decoded.t_k_numer, receipt.t_k_numer);
        assert_eq!(decoded.t_k_denom, receipt.t_k_denom);
        // timestamp_ns is NOT transmitted
        assert_eq!(decoded.timestamp_ns, 0);
    }

